theory.bad_example:
from flask import request

@app.route("/hello")
def hello():
    name = request.args.get("name", "гость")
    return f"<h1>Привет, {name}!</h1>"  # уязвимо: name попадает в HTML напрямую

theory.good_example:
from flask import request, render_template

@app.route("/hello")
def hello():
    name = request.args.get("name", "гость")
    return render_template("hello.html", name=name)  # шаблон экранирует {{ name }} по умолчанию
